// The det-fn ensures is `(antecedent) ==> det_set_equal(...)`. The
// antecedent (the four conjuncts of the original `set` ensures) is *not*
// a free hypothesis in the prelude — that is why the previous attempt's
// bare `assert(post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))`
// failed: it was checked unconditionally.
//
// Repair: case-split on the antecedent with a proof-mode `if`. Inside the
// taken branch the four conjuncts hold and we can prove the post-state
// equalities; outside, the implication is vacuously true.
if post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out)
    && post1_self_.wf()
    && post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)
    && post2_self_.wf()
{
    // Both views are extensionally equal to the same `update(...)` of
    // `pre_self_.seq@`, so they are extensionally equal to each other.
    assert(post1_self_.seq@ =~= post2_self_.seq@);
    // Lift the extensional equality to ordinary equality on `Seq<A>`.
    assert(post1_self_.seq@ == post2_self_.seq@);
    // Equality of the `Ghost`-wrapped `seq` field follows pointwise from
    // equality of the contained sequence values.
    assert(post1_self_.seq == post2_self_.seq);
    // `r1 : ()` and `r2 : ()`, so they are trivially equal.
    assert(r1 == r2);
}
